import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { experiencesService } from '../services/experiences'; // تأكد من وجود السيرفس
import axios from 'axios';
import api from '../services/api';
import './CreateExperience.css'; // تأكد من إنشاء ملف CSS بهذا الاسم

// ─── helpers ─────────────────────────────────────────────────────────────────
const emptySection = () => ({ id: Date.now(), title: '', description: '', order: 0, lectures: [] });
const emptyLecture = (sId) => ({
  id: Date.now() + Math.random(),
  sectionLocalId: sId,
  title: '', 
  description: '',
  video_type: 'upload',
  video_url: '', 
  file: null, 
  s3_key: '',
  duration_minutes: 0, 
  order: 0,
  is_free_preview: false,
  uploadProgress: 0,
  uploadStatus: '', // '' | 'uploading' | 'done' | 'error'
});

// ─── Video Type Selector ──────────────────────────────────────────────────────
const VideoTypeSelector = ({ value, onChange }) => {
  const options = [
    { value: 'upload',  label: 'رفع فيديو',  icon: '☁️', desc: 'S3 Upload' },
    { value: 'youtube', label: 'YouTube',     icon: '▶',  desc: 'رابط YouTube' },
    { value: 'vimeo',   label: 'Vimeo',       icon: '▶',  desc: 'رابط Vimeo' },
  ];
  return (
    <div className="video-type-selector">
      {options.map((o) => (
        <button
          key={o.value}
          type="button"
          className={`vt-option ${value === o.value ? 'active' : ''}`}
          onClick={() => onChange(o.value)}
        >
          <span className="vt-icon">{o.icon}</span>
          <span className="vt-label">{o.label}</span>
          <span className="vt-desc">{o.desc}</span>
        </button>
      ))}
    </div>
  );
};

// ─── component ────────────────────────────────────────────────────────────────
const CreateExperience = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  const [expData, setExpData] = useState({ title: '', description: '', price: '', image: null });
  const [imagePreview, setImagePreview] = useState(null);
  const [sections, setSections] = useState([emptySection()]);
  const [submitting, setSubmitting] = useState(false);

  // التحقق من الصلاحيات
  if (!user || !user.is_instructor) {
    alert('فقط المدرّسين يمكنهم إنشاء تجارب');
    navigate('/');
    return null;
  }

  // ── Handlers ─────────────────────────────────────────────────────────────
  const handleExpChange = (e) => {
    const { name, value, files } = e.target;
    if (files) {
      setExpData((p) => ({ ...p, [name]: files[0] }));
      setImagePreview(URL.createObjectURL(files[0]));
    } else {
      setExpData((p) => ({ ...p, [name]: value }));
    }
  };

  const addSection    = () => setSections((p) => [...p, { ...emptySection(), order: p.length }]);
  const removeSection = (id) => setSections((p) => p.filter((s) => s.id !== id));
  const updateSection = (id, field, val) =>
    setSections((p) => p.map((s) => s.id === id ? { ...s, [field]: val } : s));

  const addLecture    = (sId) =>
    setSections((p) => p.map((s) => s.id === sId
      ? { ...s, lectures: [...s.lectures, { ...emptyLecture(sId), order: s.lectures.length }] }
      : s));
  const removeLecture = (sId, lId) =>
    setSections((p) => p.map((s) => s.id === sId
      ? { ...s, lectures: s.lectures.filter((l) => l.id !== lId) }
      : s));
  const updateLecture = (sId, lId, field, val) =>
    setSections((p) => p.map((s) => s.id === sId
      ? { ...s, lectures: s.lectures.map((l) => l.id === lId ? { ...l, [field]: val } : l) }
      : s));

  // ── S3 upload ─────────────────────────────────────────────────────────────
  const uploadVideoToS3 = async (sId, lId, file) => {
    updateLecture(sId, lId, 'uploadStatus', 'uploading');
    updateLecture(sId, lId, 'uploadProgress', 0);
    try {
      // تعديل الـ endpoint ليتناسب مع التجارب لو لزم الأمر
      const { data } = await api.post('/experiences/lectures/presigned-upload/', {
        file_name: file.name,
        file_type: file.type,
      });
      await axios.put(data.upload_url, file, {
        headers: { 'Content-Type': file.type },
        onUploadProgress: (e) =>
          updateLecture(sId, lId, 'uploadProgress', Math.round((e.loaded / e.total) * 100)),
      });
      updateLecture(sId, lId, 's3_key', data.s3_key);
      updateLecture(sId, lId, 'uploadStatus', 'done');
    } catch (err) {
      console.error('S3 upload failed', err);
      updateLecture(sId, lId, 'uploadStatus', 'error');
    }
  };

  // ── Submit ────────────────────────────────────────────────────────────────
  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      const fd = new FormData();
      fd.append('title', expData.title);
      fd.append('description', expData.description);
      fd.append('price', expData.price);
      if (expData.image) fd.append('image', expData.image);

      const expRes = await experiencesService.create(fd);
      const expId  = expRes.id;

      for (let si = 0; si < sections.length; si++) {
        const sec    = sections[si];
        const secRes = await api.post('/experiences/sections/', {
          experience: expId, 
          title: sec.title, 
          description: sec.description, 
          order: si,
        });
        const sectionId = secRes.data.id;

        for (let li = 0; li < sec.lectures.length; li++) {
          const lec = sec.lectures[li];
          if (lec.video_type === 'upload' && !lec.s3_key) {
            alert(`الليكتشر "${lec.title}" لسه ما اترفعش على S3`);
            setSubmitting(false);
            return;
          }
          await api.post('/experiences/lectures/', {
            section: sectionId,
            title: lec.title, 
            description: lec.description,
            video_type: lec.video_type,
            video_url: lec.video_type !== 'upload' ? lec.video_url : '',
            s3_key:    lec.video_type === 'upload'  ? lec.s3_key   : '',
            duration_minutes: lec.duration_minutes,
            order: li, 
            is_free_preview: lec.is_free_preview,
          });
        }
      }
      alert('تم إنشاء التجربة بنجاح! في انتظار موافقة الأدمن.');
      navigate('/experiences');
    } catch (err) {
      alert('فشل إنشاء التجربة: ' + (err.response?.data?.detail || 'حدث خطأ'));
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="exp-page">
      <div className="exp-container">

        <div className="exp-page-header">
          <h1 className="exp-title">إنشاء تجربة جديدة</h1>
          <p className="exp-subtitle">أضف محتواك التعليمي الفريد وانتظر موافقة الإدارة</p>
        </div>

        <form onSubmit={handleSubmit}>

          {/* ── Experience Info ──────────────────────────────────────────── */}
          <div className="exp-card">
            <div className="exp-card-header">
              <span className="exp-card-icon">🧪</span>
              <h2>معلومات التجربة</h2>
            </div>

            <div className="exp-field">
              <label>عنوان التجربة <span className="req">*</span></label>
              <input
                className="exp-input"
                name="title"
                value={expData.title}
                onChange={handleExpChange}
                placeholder="مثال: تجربة عملية في البرمجة"
                required
              />
            </div>

            <div className="exp-field">
              <label>وصف التجربة <span className="req">*</span></label>
              <textarea
                className="exp-input exp-textarea"
                name="description"
                value={expData.description}
                onChange={handleExpChange}
                placeholder="اشرح تفاصيل التجربة وما سيحصل عليه المتعلم..."
                required
              />
            </div>

            <div className="exp-field-row">
              <div className="exp-field">
                <label>السعر (EGP) <span className="req">*</span></label>
                <input
                  className="exp-input"
                  type="number"
                  name="price"
                  value={expData.price}
                  onChange={handleExpChange}
                  min="0" step="0.01"
                  placeholder="0.00"
                  required
                />
              </div>

              <div className="exp-field">
                <label>صورة الغلاف</label>
                <div className="exp-image-upload">
                  {imagePreview ? (
                    <div className="image-preview-wrap">
                      <img src={imagePreview} alt="preview" className="image-preview" />
                      <label className="image-change-btn">
                        تغيير الصورة
                        <input type="file" name="image" accept="image/*"
                          onChange={handleExpChange} hidden />
                      </label>
                    </div>
                  ) : (
                    <label className="image-drop-zone">
                      <span className="drop-icon">🖼️</span>
                      <span className="drop-text">اختر صورة الغلاف</span>
                      <input type="file" name="image" accept="image/*"
                        onChange={handleExpChange} hidden />
                    </label>
                  )}
                </div>
              </div>
            </div>
          </div>

          {/* ── Sections ─────────────────────────────────────────────── */}
          <div className="exp-card">
            <div className="exp-card-header">
              <span className="exp-card-icon">📑</span>
              <h2>المراحل والدروس</h2>
              <button type="button" className="exp-btn-add-section" onClick={addSection}>
                + مرحلة جديدة
              </button>
            </div>

            {sections.map((sec, si) => (
              <div key={sec.id} className="exp-section">
                <div className="exp-section-header">
                  <div className="section-num">المرحلة {si + 1}</div>
                  <div className="exp-section-fields">
                    <input
                      className="exp-input"
                      value={sec.title}
                      onChange={(e) => updateSection(sec.id, 'title', e.target.value)}
                      placeholder="عنوان المرحلة"
                      required
                    />
                    <input
                      className="exp-input"
                      value={sec.description}
                      onChange={(e) => updateSection(sec.id, 'description', e.target.value)}
                      placeholder="وصف المرحلة (اختياري)"
                    />
                  </div>
                  {sections.length > 1 && (
                    <button type="button" className="exp-btn-remove" onClick={() => removeSection(sec.id)}>
                      🗑
                    </button>
                  )}
                </div>

                <div className="exp-lectures">
                  {sec.lectures.map((lec, li) => (
                    <div key={lec.id} className="exp-lecture">
                      <div className="exp-lecture-header">
                        <span className="lec-num">#{li + 1}</span>
                        <input
                          className="exp-input lec-title-input"
                          value={lec.title}
                          onChange={(e) => updateLecture(sec.id, lec.id, 'title', e.target.value)}
                          placeholder="عنوان الدرس"
                          required
                        />
                        <button type="button" className="exp-btn-remove"
                          onClick={() => removeLecture(sec.id, lec.id)}>🗑</button>
                      </div>

                      <div className="exp-field">
                        <label className="exp-field-label">نوع المحتوى</label>
                        <VideoTypeSelector
                          value={lec.video_type}
                          onChange={(v) => updateLecture(sec.id, lec.id, 'video_type', v)}
                        />
                      </div>

                      {lec.video_type === 'upload' ? (
                        <div className="exp-field">
                          <label className="exp-field-label">ملف الفيديو</label>
                          <div className="upload-zone">
                            {lec.uploadStatus === 'done' ? (
                              <div className="upload-done">
                                <span>✅ تم الرفع بنجاح</span>
                                <label className="re-upload-link">
                                  تغيير الفيديو
                                  <input type="file" accept="video/*" hidden
                                    onChange={(e) => updateLecture(sec.id, lec.id, 'file', e.target.files[0])} />
                                </label>
                              </div>
                            ) : lec.uploadStatus === 'uploading' ? (
                              <div className="upload-progress-wrap">
                                <div className="upload-progress-bar">
                                  <div className="upload-progress-fill" style={{ width: `${lec.uploadProgress}%` }} />
                                </div>
                                <span className="pct">{lec.uploadProgress}%</span>
                              </div>
                            ) : (
                              <>
                                <label className="file-drop-label">
                                  <span>{lec.file ? lec.file.name : 'اختر ملف فيديو'}</span>
                                  <input type="file" accept="video/*" hidden
                                    onChange={(e) => updateLecture(sec.id, lec.id, 'file', e.target.files[0])} />
                                </label>
                                {lec.file && (
                                  <button type="button" className="btn-upload-s3"
                                    onClick={() => uploadVideoToS3(sec.id, lec.id, lec.file)}>
                                    ⬆ ارفع الآن
                                  </button>
                                )}
                              </>
                            )}
                          </div>
                        </div>
                      ) : (
                        <div className="exp-field">
                          <label className="exp-field-label">الرابط المباشر</label>
                          <input
                            className="exp-input"
                            type="url"
                            placeholder="https://..."
                            value={lec.video_url}
                            onChange={(e) => updateLecture(sec.id, lec.id, 'video_url', e.target.value)}
                          />
                        </div>
                      )}

                      <div className="exp-lecture-footer">
                        <div className="exp-field inline">
                          <label className="exp-field-label">المدة (دقائق)</label>
                          <input
                            className="exp-input duration-input"
                            type="number"
                            value={lec.duration_minutes}
                            onChange={(e) => updateLecture(sec.id, lec.id, 'duration_minutes', +e.target.value)}
                          />
                        </div>

                        <label className="free-preview-toggle">
                          <div className={`toggle-switch ${lec.is_free_preview ? 'on' : ''}`}
                            onClick={() => updateLecture(sec.id, lec.id, 'is_free_preview', !lec.is_free_preview)}>
                            <div className="toggle-thumb" />
                          </div>
                          <span>معاينة مجانية</span>
                        </label>
                      </div>
                    </div>
                  ))}

                  <button type="button" className="exp-btn-add-lecture"
                    onClick={() => addLecture(sec.id)}>
                    + درس جديد
                  </button>
                </div>
              </div>
            ))}
          </div>

          <div className="exp-submit-row">
            <button type="button" className="exp-btn-cancel" onClick={() => navigate(-1)}>
              إلغاء
            </button>
            <button type="submit" className="exp-btn-submit" disabled={submitting}>
              {submitting ? 'جاري الإنشاء...' : '🚀 إنشاء التجربة'}
            </button>
          </div>

        </form>
      </div>
    </div>
  );
};

export default CreateExperience;
